SELECT EXISTS (
  SELECT 1
  FROM sessions
  WHERE session_id = $1
    AND expires_at > NOW()
) AS session_exists;

SELECT EXISTS (
  SELECT 1
  FROM users
  WHERE email = $1
) AS user_exists;

DELETE FROM user_otps
WHERE email = $1
  AND otp_code = $2;

